def main(arg1: dict) -> dict:
    import json, re
    data = json.loads(arg1.get('body', '{}'))
    items = data.get('items', [])

    def clean_html(html):
        if not html: return ''
        text = re.sub(r'<[^>]+>', ' ', html)
        text = re.sub(r'https?://\S+', '', text)
        return ' '.join(text.split())[:300]

    parsed = []
    for item in items:
        parsed.append({
            'id': item.get('id', ''),
            'title': item.get('title', ''),
            'summary': clean_html(item.get('summary', {}).get('content', '')),
            'source': item.get('origin', {}).get('title', '未知来源'),
            'link': item.get('alternate', [{}])[0].get('href', ''),
            'published': item.get('published', 0)
        })

    return {'items': parsed, 'count': len(parsed)}

def main(arg1: str) -> dict:
    import json, re
    text = arg1
    if '```json' in text:
        json_str = text.split('```json')[1].split('```')[0].strip()
    elif '```' in text:
        json_str = text.split('```')[1].strip()
    else:
        start = text.find('{')
        end = text.rfind('}')
        json_str = text[start:end+1] if start != -1 and end != -1 else text
    try:
        return json.loads(json_str)
    except:
        return {'topics': [], 'error': '解析失败'}

def main(arg1: dict, arg2: dict) -> dict:
    topics = arg1.get('topics', [])
    items = arg2.get('items', [])

    for topic in topics:
        source_links = []
        seen_urls = set()
        for sid in topic.get('source_ids', []):
            idx = sid - 1
            if 0 <= idx < len(items):
                item = items[idx]
                url = item.get('link', '')
                if url and url not in seen_urls:
                    source_links.append({'name': item.get('source', ''), 'url': url})
                    seen_urls.add(url)
        topic['sourceLinks'] = source_links[:5]
        topic['sources'] = len(source_links)

    return {'topics': topics, 'count': len(topics)}

def main(arg1: dict) -> dict:
    from datetime import datetime
    import json

    topics = arg1.get('topics', [])
    today = datetime.now().strftime('%Y-%m-%d')

    data = {
        'date': today,
        'topics': topics,
        'summary': {
            'total': len(topics),
            'high': len([t for t in topics if t.get('score', 0) >= 75]),
            'themes': [t.get('entity', '') for t in topics[:5]]
        }
    }

    return {
        'json_content': json.dumps(data, ensure_ascii=False, indent=2),
        'filename': f'inoreader_topics_{today.replace("-", "")}_claude_format.json'
    }
